const items = $input.all();

// n8n HTTP Request unpacks array — each item IS already a blog
const blogs = items.map(item => item.json);

if (!blogs || blogs.length === 0) return [];

return blogs.map(blog => ({ json: { ...blog } }));

const d = $json;

// 1. Save to blog API
await this.helpers.httpRequest({
  method: 'POST',
  url: `http://172.17.0.1:8000/api/blogs/${d.blog.id}/posts`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    title:   d.topic,
    content: d.content,
    category: d.format
  }),
  ignoreHttpStatusErrors: true
});

// 2. Post to Telegram channel if configured
if (d.blog.telegram_channel) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN}/sendMessage`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      chat_id: d.blog.telegram_channel,
      text:    d.content
    }),
    ignoreHttpStatusErrors: true
  });
}

return [{ json: { status: 'published', blog: d.blog.id } }];

